 1→/**
 2→ * PrismaClient singleton
 3→ *
 4→ * Avoids "too many Prisma Clients" error in development due to hot-reloading.
 5→ * Enables query logging in development for observability.
 6→ */
 7→
 8→import { PrismaClient } from '@prisma/client';
 9→
10→// Global singleton pattern
11→const globalForPrisma = globalThis as unknown as {
12→  prisma: PrismaClient | undefined;
13→};
14→
15→/**
16→ * Singleton PrismaClient instance
17→ * Reuses existing instance in hot-reload scenarios
18→ */
19→export const prisma =
20→  globalForPrisma.prisma ??
21→  new PrismaClient({
22→    log: process.env.NODE_ENV === 'development'
23→      ? ['query', 'error', 'warn']
24→      : ['error'],
25→  });
26→
27→if (process.env.NODE_ENV !== 'production') {
28→  globalForPrisma.prisma = prisma;
29→}
30→
31→/**
32→ * Graceful shutdown hook
33→ * Call this before process exit to close database connections
34→ */
35→export async function disconnectPrisma(): Promise<void> {
36→  await prisma.$disconnect();
37→}
38→
39→export default prisma;
